          {(['all', 'users', 'posts'] as Tab[]).map(tab => (
            <Chip
              key={tab}
              label={tab.charAt(0).toUpperCase() + tab.slice(1)}
              active={activeTab === tab}
              onPress={() => setActiveTab(tab)}
            />
          ))}
        </ScrollView>

        {normalizedQuery.length < 2 ? (
          <EmptyState
            icon={<SearchIcon size={40} color={colors.textFaint} />}
            title="Search iskrib"
            subtitle="Find writers and stories that inspire you"
          />
        ) : (
          <FlatList
            data={[]}
            renderItem={null}
            showsVerticalScrollIndicator={false}
            contentContainerStyle={styles.results}
            ListHeaderComponent={
              <>
                {/* Users section */}
                {activeTab !== 'posts' && users.length > 0 && (
                  <View style={styles.section}>
                    <Text style={[styles.sectionTitle, {color: colors.textHeading}]}>
                      Users
                    </Text>
                    {users.map(u => (
                      <Pressable
                        key={u.id}
                        style={[styles.userRow, {borderBottomColor: colors.borderCard}]}
                        onPress={() =>
                          navigation.navigate('VisitProfile', {
                            userId: u.id,
                            username: u.username ?? undefined,
                          })
                        }>
                        <Avatar uri={u.image_url} name={u.name ?? undefined} size={40} />
                        <View style={styles.userInfo}>
                          <Text style={[styles.userName, {color: colors.textPrimary}]}>
                            {u.name || 'Unknown'}
                          </Text>
                          {u.username && (
                            <Text style={[styles.userHandle, {color: colors.textMuted}]}>
                              @{u.username}
                            </Text>
                          )}
                        </View>
                      </Pressable>
                    ))}
                  </View>
                )}

                {/* Journals section */}
                {activeTab !== 'users' && journals.length > 0 && (
                  <View style={styles.section}>
                    <Text style={[styles.sectionTitle, {color: colors.textHeading}]}>
                      Posts
                    </Text>
                    {journals.map(j => (
                      <Pressable
                        key={j.id}
                        style={[styles.journalRow, {borderBottomColor: colors.borderCard}]}
                        onPress={() =>
                          navigation.navigate('PostDetail', {journalId: j.id})
                        }>
                        <Text
                          style={[styles.journalTitle, {color: colors.textPrimary}]}
                          numberOfLines={1}>
                          {j.title || 'Untitled Post'}
                        </Text>
                        <Text style={[styles.journalAuthor, {color: colors.textMuted}]}>
                          {j.users?.name || 'Unknown'}
                        </Text>
                      </Pressable>
                    ))}
                  </View>
                )}

                {/* Empty results */}
                {activeTab !== 'posts' && users.length === 0 &&
                 activeTab !== 'users' && journals.length === 0 && (
                  <EmptyState
                    title="No results"
                    subtitle={`Nothing found for "${normalizedQuery}"`}
                  />
                )}
              </>
            }
          />
        )}
      </View>
    </SafeAreaView>
  );
}

