 45→  BottomTabScreenProps<MainTabParamList, 'Explore'>,
 46→  NativeStackScreenProps<RootStackParamList>
 47→>;
 48→
 49→type Tab = 'all' | 'users' | 'posts';
 50→
 51→const getHotScore = (journal: JournalItem): number => {
 52→  if (typeof journal.hot_score === 'number') return journal.hot_score;
 53→  const likes = resolveCount(journal.like_count, journal.likes_count);
 54→  const comments = resolveCount(journal.comment_count, journal.comments_count);
 55→  const bookmarks = resolveCount(journal.bookmark_count);
 56→  return likes + comments * 2 + bookmarks * 3;
 57→};
